import{_ as t,o as s,c as n,a2 as e}from"./chunks/framework.Wufm-cgV.js";const u=JSON.parse('{"title":"优化特性","description":"wr-proxy 请求优化 — Token 压缩、会话压缩与动态内容重排","frontmatter":{"title":"优化特性","description":"wr-proxy 请求优化 — Token 压缩、会话压缩与动态内容重排"},"headers":[],"relativePath":"zh/guide/optimization.md","filePath":"zh/guide/optimization.md"}'),o={name:"zh/guide/optimization.md"};function p(d,a,i,r,l,c){return s(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="优化特性" tabindex="-1">优化特性 <a class="header-anchor" href="#优化特性" aria-label="Permalink to &quot;优化特性&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>wr-proxy 内置请求优化功能，在请求到达上游 Provider 前自动转换——降低 Token 成本、提升缓存命中率、优雅处理长对话。</p><p>所有功能通过系统设置控制，可独立开关，无需重启 wr-proxy。</p><h2 id="功能开关" tabindex="-1">功能开关 <a class="header-anchor" href="#功能开关" aria-label="Permalink to &quot;功能开关&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>设置键</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td>动态内容重排</td><td><code>feature_dynamic_content_last</code></td><td>关闭</td><td>将动态内容移至上下文末尾</td></tr><tr><td>Token 压缩</td><td><code>feature_token_compression</code></td><td>关闭</td><td>压缩超长 system prompt</td></tr><tr><td>会话压缩</td><td><code>feature_session_compression</code></td><td>关闭</td><td>摘要长对话历史</td></tr></tbody></table><p>在管理面板 <strong>系统设置</strong> 或 <code>PUT /api/settings</code> 中切换。</p><h2 id="_1-动态内容重排" tabindex="-1">1. 动态内容重排 <a class="header-anchor" href="#_1-动态内容重排" aria-label="Permalink to &quot;1. 动态内容重排&quot;">​</a></h2><h3 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h3><p>当动态内容（URL、时间戳、哈希值）出现在对话前部时，会阻止上游 prompt 缓存生效——即使核心指令未变，每次请求看起来都&quot;不同&quot;。</p><h3 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h3><p>wr-proxy 检测包含动态模式的消息，并在其 role 组内重排——将动态消息推到末尾：</p><table tabindex="0"><thead><tr><th>模式</th><th>示例</th></tr></thead><tbody><tr><td>URL</td><td><code>https://api.example.com/v1/...</code></td></tr><tr><td>日期</td><td><code>2026-06-07</code></td></tr><tr><td>时间</td><td><code>14:30:00</code></td></tr><tr><td>哈希/UUID</td><td><code>a1b2c3d4e5f6...</code></td></tr><tr><td>长数字</td><td><code>1234567890123</code></td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>重排前：                          重排后：</span></span>
<span class="line"><span>[system: &quot;你是...&quot;]               [system: &quot;你是...&quot;]</span></span>
<span class="line"><span>[user: &quot;检查 https://...&quot;]        [user: &quot;状态怎么样？&quot;]</span></span>
<span class="line"><span>[user: &quot;状态怎么样？&quot;]              [user: &quot;检查 https://...&quot;]  ← 移到末尾</span></span></code></pre></div><p>效果：静态前缀在上游保持可缓存。</p><h2 id="_2-token-压缩-rtk" tabindex="-1">2. Token 压缩（RTK） <a class="header-anchor" href="#_2-token-压缩-rtk" aria-label="Permalink to &quot;2. Token 压缩（RTK）&quot;">​</a></h2><h3 id="问题-1" tabindex="-1">问题 <a class="header-anchor" href="#问题-1" aria-label="Permalink to &quot;问题&quot;">​</a></h3><p>超长 system prompt（2000+ 字符）每次请求都消耗 Token，即使指令几乎不变。</p><h3 id="解决方案-1" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案-1" aria-label="Permalink to &quot;解决方案&quot;">​</a></h3><p>启用后，超过阈值的 system prompt 被原地压缩：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始（3000 字符）：</span></span>
<span class="line"><span>&quot;你是一位专业代码审查员。遵循以下准则：</span></span>
<span class="line"><span> 1. 检查安全漏洞...</span></span>
<span class="line"><span> 2. 验证错误处理...</span></span>
<span class="line"><span> ... (还有 2000 字符) ...</span></span>
<span class="line"><span> 99. 确保命名一致...&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>压缩后：</span></span>
<span class="line"><span>&quot;你是一位专业代码审查员。遵循以下准则：</span></span>
<span class="line"><span> 1. 检查安全漏洞...</span></span>
<span class="line"><span> 2. 验证错误处理...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[... 2300 字符省略 ...]</span></span>
<span class="line"><span></span></span>
<span class="line"><span> 98. 使用类型提示。</span></span>
<span class="line"><span> 99. 确保命名一致。&quot;</span></span></code></pre></div><p>模型收到紧凑表示，同时保留关键的首尾指令。</p><h2 id="_3-会话压缩" tabindex="-1">3. 会话压缩 <a class="header-anchor" href="#_3-会话压缩" aria-label="Permalink to &quot;3. 会话压缩&quot;">​</a></h2><h3 id="问题-2" tabindex="-1">问题 <a class="header-anchor" href="#问题-2" aria-label="Permalink to &quot;问题&quot;">​</a></h3><p>长对话（10+ 轮）累积显著 Token 成本。早期消息可能与当前话题无关。</p><h3 id="解决方案-2" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案-2" aria-label="Permalink to &quot;解决方案&quot;">​</a></h3><p>当对话超过压缩阈值时，wr-proxy：</p><ol><li>完整保留最近 5 轮</li><li>将早期轮次摘要为简洁的系统消息</li><li>在最近消息前注入摘要</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>压缩前（15 轮）：                    压缩后：</span></span>
<span class="line"><span>[system: &quot;你是...&quot;]                 [system: &quot;你是...&quot;]</span></span>
<span class="line"><span>[第1轮: user/assistant]             [system: &quot;[第1-10轮摘要]</span></span>
<span class="line"><span>[第2轮: user/assistant]              共 10 轮对话，约 5000 字符。</span></span>
<span class="line"><span> ...                                 主要话题：部署流程、数据库配置...&quot;]</span></span>
<span class="line"><span>[第10轮: user/assistant]            [第11轮: user/assistant]  ← 保留</span></span>
<span class="line"><span>[第11轮: user/assistant]            [第12轮: user/assistant]</span></span>
<span class="line"><span> ...                                ...</span></span>
<span class="line"><span>[第15轮: user/assistant]            [第15轮: user/assistant]</span></span></code></pre></div><h2 id="会话上下文感知" tabindex="-1">会话上下文感知 <a class="header-anchor" href="#会话上下文感知" aria-label="Permalink to &quot;会话上下文感知&quot;">​</a></h2><p>除了三个可开关的功能外，wr-proxy 的智能模型选择也会考虑会话上下文：</p><ul><li><strong>大上下文</strong>（累积 &gt;16K tokens）：复杂度评分 +0.15，可能触发 premium 模型选择</li><li><strong>中等上下文</strong>（&gt;8K tokens）：复杂度评分 +0.08</li></ul><p>确保对话越深入，模型选择越适配。</p><h2 id="api-兼容性" tabindex="-1">API 兼容性 <a class="header-anchor" href="#api-兼容性" aria-label="Permalink to &quot;API 兼容性&quot;">​</a></h2><p>三项优化功能同样支持 Anthropic（<code>/v1/messages</code>）和 Cohere（<code>/v1/chat</code>）API 格式，在优化前先进行格式转换。</p><h2 id="管理端点" tabindex="-1">管理端点 <a class="header-anchor" href="#管理端点" aria-label="Permalink to &quot;管理端点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>端点</th><th>说明</th></tr></thead><tbody><tr><td><code>GET /admin/features</code></td><td>查看当前功能开关状态</td></tr><tr><td><code>POST /admin/features</code></td><td>从数据库重新加载功能开关</td></tr><tr><td><code>POST /admin/conversation_compress</code></td><td>手动触发会话压缩</td></tr></tbody></table>`,37)])])}const b=t(o,[["render",p]]);export{u as __pageData,b as default};
